import pandas as pd
import re

# Get project info data
project_data = locals()['var_functions.query_db:14']

# Extract star counts from Project_Information
def extract_stars(info_text):
    """Extract stars count from Project_Information text"""
    if not info_text or 'stars count' not in info_text:
        return 0

    # Look for patterns like "stars count of 38715" or "stars count: 3761"
    match = re.search(r'stars count[\s,:]+(\d+)', info_text)
    if match:
        return int(match.group(1))
    return 0

# Test the extraction
sample_projects = []
for item in project_data:
    stars = extract_stars(item['Project_Information'])
    sample_projects.append({
        'Project_Information': item['Project_Information'],
        'Stars': stars
    })

print('__RESULT__:')
print(json.dumps(sample_projects, indent=2))"}

